class Solution:
    def minDifference(self, nums):
        n = len(nums)
        if n <= 4:
            return 0
        if n <= 10:
            import itertools
            idxs = range(n)
            best = None
            for k in range(0, 4):
                for removed in itertools.combinations(idxs, k):
                    removed_set = set(removed)
                    kept = [nums[i] for i in idxs if i not in removed_set]
                    diff = max(kept) - min(kept)
                    if best is None or diff < best:
                        best = diff
            return best
        s = sorted(nums)
        best = None
        for i in range(4):
            diff = s[n - 4 + i] - s[i]
            if best is None or diff < best:
                best = diff
        return best

