var minDifference = function(nums) {
    const sorted = [...nums].sort((a, b) => a - b);
    const n = sorted.length;
    if (n <= 4) return 0;
    let best = Infinity;
    for (let i = 0; i < 4; i++) {
        const diff = sorted[n - 4 + i] - sorted[i];
        if (diff < best) best = diff;
    }
    return best;
};
